transformTemplates:
($arm64 := $._embedded.firmware[platform = "linux-arm64"]; $x64 := $._embedded.firmware[platform = "linux-x64"]; {"releases": [{"version": $replace($x64.version, /^v/, ""), "digest": "archConfig =
    {
      "aarch64-linux" = {
        src.url = "" & $arm64._links.data.href & "";
        src.hash = "sha256:" & $arm64.sha256_checksum & "";
        firmwarePlatform = "linux-arm64";
      };
      "x86_64-linux" = {
        src.url = "" & $x64._links.data.href & "";
        src.hash = "sha256:" & $x64.sha256_checksum & "";
        firmwarePlatform = "linux-x64";
      };
    }"}]})

matchStrings:
version = "(?<currentValue>[^"]+)";
  (?<currentDigest>archConfig =
    \{
      "aarch64-linux" = \{
        src\.url = "[^"]+";
        src\.hash = "sha256:[^"]+";
        firmwarePlatform = "linux-arm64";
      \};
      "x86_64-linux" = \{
        src\.url = "[^"]+";
        src\.hash = "sha256:[^"]+";
        firmwarePlatform = "linux-x64";
      \};
    \})
